var totalWaviness = function(num1, num2) {
    function cumWaviness(N) {
        if (N <= 0) return 0;
        const s = String(N);
        const L = s.length;
        const digits = [...s].map(Number);
        let total = 0;

        function freeDp(length) {
            const memo = new Map();
            function rec(idx, p2, p1) {
                if (idx === length) return [1, 0];
                const key = idx + ',' + p2 + ',' + p1;
                if (memo.has(key)) return memo.get(key);
                let cntTotal = 0, sumTotal = 0;
                const lo = idx === 0 ? 1 : 0;
                for (let d = lo; d <= 9; d++) {
                    let contrib = 0;
                    if (idx >= 2 && ((p2 < p1 && p1 > d) || (p2 > p1 && p1 < d))) contrib = 1;
                    const [subcnt, subsum] = rec(idx + 1, p1, d);
                    cntTotal += subcnt;
                    sumTotal += subsum + contrib * subcnt;
                }
                const res = [cntTotal, sumTotal];
                memo.set(key, res);
                return res;
            }
            const [, sm] = rec(0, -1, -1);
            return sm;
        }

        for (let length = 1; length < L; length++) total += freeDp(length);

        const memoTight = new Map();
        function recTight(idx, p2, p1, tight) {
            if (idx === L) return [1, 0];
            const key = idx + ',' + p2 + ',' + p1 + ',' + (tight ? 1 : 0);
            if (memoTight.has(key)) return memoTight.get(key);
            let cntTotal = 0, sumTotal = 0;
            const hi = tight ? digits[idx] : 9;
            const lo = idx === 0 ? 1 : 0;
            for (let d = lo; d <= hi; d++) {
                let contrib = 0;
                if (idx >= 2 && ((p2 < p1 && p1 > d) || (p2 > p1 && p1 < d))) contrib = 1;
                const ntight = tight && d === hi;
                const [subcnt, subsum] = recTight(idx + 1, p1, d, ntight);
                cntTotal += subcnt;
                sumTotal += subsum + contrib * subcnt;
            }
            const res = [cntTotal, sumTotal];
            memoTight.set(key, res);
            return res;
        }
        const [, sm2] = recTight(0, -1, -1, true);
        total += sm2;
        return total;
    }
    return cumWaviness(num2) - cumWaviness(num1 - 1);
};
